60: do_proc_get_root(struct rpc_clnt *client, struct nfs_fh *fhandle,
61: 		 struct nfs_fsinfo *info)
62: {
63: 	struct rpc_message msg = {
64: 		.rpc_proc	= &nfs3_procedures[NFS3PROC_FSINFO],
65: 		.rpc_argp	= fhandle,
66: 		.rpc_resp	= info,
67: 	};
68: 	int	status;
